private void validateCallsRealMethods(CallsRealMethods answer, Invocation invocation) {
    Class<?> mockType = invocation.getMock().getClass();
    if (mockType.getSuperclass() == null || !mockType.getSuperclass().getName().startsWith("org.mockito")) {
        // If it's not a Mockito enhanced class, check the real mock type
        // Mockito creates mocks using CGLIB which generates classes that extend the mocked class or implement the interface
        // For interfaces, we need to check if the original type was an interface
        // We can check if the mock object is an instance of an interface by checking the mocked type from the invocation
        // The invocation's method can help us determine if it's from an interface
        if (invocation.getMethod().getDeclaringClass().isInterface()) {
            reporter.cannotCallRealMethodsOnInterface();
        }
    }
}

